        let mut clause = format!("INNER JOIN {} ON {}", table.into(), on_clause.into());
        let mut incoming: Vec<BindValue> = binds.into_iter().map(Into::into).collect();
        let mut idx = self.join_binds.len() + self.binds.len() + 1;
